UPDATE [dbo].TB_FS_BILL
   SET SSMM        = #{ssmm}
     , MDFR_ID     = #{mdfr_id}
     , MDFR_DT     = GETDATE()
 WHERE STATUS      = 'Y'
   AND SYS_ID  = #{sys_id}
   AND FS_BILL_NO  = #{fs_bill_no}
   AND FS_BILL_SEQ = #{fs_bill_seq}

UPDATE [dbo].TB_FS_BILL
   SET STATUS      = 'N'
     , MDFR_ID     = #{mdfr_id}
     , MDFR_DT     = GETDATE()
 WHERE STATUS      = 'Y'
   AND SYS_ID  = #{sys_id}
   AND FS_BILL_NO  = #{fs_bill_no}
   AND FS_BILL_SEQ = #{fs_bill_seq}

        UPDATE [dbo].TB_FS_ESTMATE
           SET FS_BILL_YN    = 'N'
             , MDFR_ID       = #{mdfr_id}
             , MDFR_DT       = GETDATE()
		  FROM [dbo].TB_FS_ESTMATE A
		 INNER JOIN [dbo].TB_FS_BILL B
			ON A.SYS_ID      = B.SYS_ID
		   AND A.FS_BILL_NO  = B.FS_BILL_NO
		 WHERE A.SYS_ID      = #{sys_id} 
           AND A.FS_BILL_NO  = #{fs_bill_no}

UPDATE [dbo].TB_FS_BILL
   SET BILL_REQ_CD = #{bill_req_cd}


     , BILL_REQ_DATE = GETDATE()


     , BILL_REP_DATE = GETDATE()


     , BILL_MDIFY_NOTE = #{bill_mdify_note}
     , BILL_MDIFY_DATE = GETDATE()


     , MDFR_ID     = #{mdfr_id}
     , MDFR_DT     = GETDATE()
 WHERE STATUS      = 'Y'
   AND SYS_ID  = #{sys_id}
   AND FS_BILL_NO  = #{fs_bill_no}
   AND FS_BILL_SEQ = #{fs_bill_seq}
